### **Improved Version with Security Best Practices:**

```javascript
// Enhanced version with security and error handling
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');
const app = express();

// ============================================
// SECURITY MIDDLEWARE
// ============================================

// 1. Security headers
app.use(helmet());

// 2. Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// 3. Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// ============================================
// LOGGING & REQUEST VALIDATION
// ============================================

// Simple logging middleware
app.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`);
  next();
});

// ============================================
// ROUTES WITH VALIDATION & ERROR HANDLING
// ============================================

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Validate optional query parameters
    const { page, limit, search } = req.query;

    // Validate pagination parameters
    const pageNum = parseInt(page, 10) || 1;
    const limitNum = parseInt(limit, 10) || 10;

    // Security: Validate and sanitize inputs
    if (pageNum < 1 || pageNum > 10000) {
      return res.status(400).json({ 
        error: 'Invalid page number. Must be between 1 and 10000.' 
      });
    }

    if (limitNum < 1 || limitNum > 100) {
      return res.status(400).json({ 
        error: 'Invalid limit. Must be between 1 and 100.' 
      });
    }

    // Sanitize search parameter if provided
    let searchFilter = null;
    if (search) {
      if (typeof search !== 'string' || search.length > 50) {
        return res.status(400).json({ 
          error: 'Search term must be a string with max 50 characters.' 
        });
      }
      searchFilter = validator.escape(search.trim());
    }

    // Mock data
    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter if search provided
    const filteredUsers = searchFilter 
      ? allUsers.filter(user => 
          user.name.toLowerCase().includes(searchFilter.toLowerCase()) ||
          user.email.toLowerCase().includes(searchFilter.toLowerCase())
        )
      : allUsers;

    // Apply pagination
    const startIdx = (pageNum - 1) * limitNum;
    const paginatedUsers = filteredUsers.slice(startIdx, startIdx + limitNum);

    res.json({
      data: paginatedUsers,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: filteredUsers.length,
      }
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ============================================
// 404 HANDLER
// ============================================
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ============================================
// GLOBAL ERROR HANDLER (Must be last)
// ============================================
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't leak error details to clients
  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(statusCode).json({ error: message });
});

// ============================================
// SERVER STARTUP
// ============================================
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

