    return res.status(500).json({ error: 'Internal server error' });
  }

  res.status(err.status || 500).json({
    error: err.message,
    stack: err.stack
  });
});

// 9. Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure server running on port ${PORT}`);
});

module.exports = app;
